const (
	TypeDataSource Type = "datasource"
	TypePanel      Type = "panel"
	TypeApp        Type = "app"
	TypeRenderer   Type = "renderer"
)

func (pt Type) IsValid() bool {
	switch pt {
	case TypeDataSource, TypePanel, TypeApp, TypeRenderer:
		return true
	}
	return false
}

