   298→// removeConnectionHeaders removes hop-by-hop headers listed in the "Connection" header of h.
   299→// See RFC 7230, section 6.1
   300→//
   301→// Based on https://github.com/golang/go/blob/dc04f3ba1f25313bc9c97e728620206c235db9ee/src/net/http/httputil/reverseproxy.go#L411-L421
   302→func removeConnectionHeaders(h map[string][]string) {
   303→	for _, f := range h["Connection"] {
   304→		for _, sf := range strings.Split(f, ",") {
   305→			if sf = textproto.TrimString(sf); sf != "" {
   306→				for k := range h {
   307→					if textproto.CanonicalMIMEHeaderKey(sf) == textproto.CanonicalMIMEHeaderKey(k) {
   308→						delete(h, k)
   309→						break
   310→					}
   311→				}
   312→			}
   313→		}
   314→	}
   315→}
   316→
   317→// Hop-by-hop headers. These are removed when sent to the backend.
   318→// As of RFC 7230, hop-by-hop headers are required to appear in the
   319→// Connection header field. These are the headers defined by the
   320→// obsoleted RFC 2616 (section 13.5.1) and are used for backward
   321→// compatibility.
   322→//
   323→// Copied from https://github.com/golang/go/blob/dc04f3ba1f25313bc9c97e728620206c235db9ee/src/net/http/httputil/reverseproxy.go#L171-L186
   324→var hopHeaders = []string{
   325→	"Connection",
   326→	"Proxy-Connection", // non-standard but still sent by libcurl and rejected by e.g. google
   327→	"Keep-Alive",
   328→	"Proxy-Authenticate",
   329→	"Proxy-Authorization",
   330→	"Te",      // canonicalized version of "TE"
   331→	"Trailer", // not Trailers per URL above; https://www.rfc-editor.org/errata_search.php?eid=4522
   332→	"Transfer-Encoding",
   333→	"Upgrade",
   334→	"User-Agent",
   335→}
   336→
   337→// removeHopByHopHeaders removes hop-by-hop headers. Especially
   338→// important is "Connection" because we want a persistent
   339→// connection, regardless of what the client sent to us.
   340→//
   341→// Based on https://github.com/golang/go/blob/dc04f3ba1f25313bc9c97e728620206c235db9ee/src/net/http/httputil/reverseproxy.go#L276-L281
   342→func removeHopByHopHeaders(h map[string][]string) {
   343→	for _, hh := range hopHeaders {
   344→		for k := range h {
   345→			if hh == textproto.CanonicalMIMEHeaderKey(k) {
   346→				delete(h, k)
   347→				break
   348→			}
   349→		}
   350→	}
   351→}
