   353→func removeNonAllowedHeaders(h map[string][]string) {
   354→	for k := range h {
   355→		if textproto.CanonicalMIMEHeaderKey(k) == setCookieHeaderName {
   356→			delete(h, k)
   357→		}
   358→	}
   359→}
